-- Auto-generated loader for user-provided Listings seed
-- It creates a transient view dbo.Listings -> dbo.MoveAdvisorMarketOffers if needed.
SET NOCOUNT ON;
SET XACT_ABORT ON;

DECLARE @createdListingsView bit = 0;
IF OBJECT_ID(N'dbo.Listings', N'U') IS NULL AND OBJECT_ID(N'dbo.Listings', N'V') IS NULL
BEGIN
  EXEC(N'CREATE VIEW dbo.Listings AS SELECT * FROM dbo.MoveAdvisorMarketOffers;');
  SET @createdListingsView = 1;
END;

BEGIN TRANSACTION;





















COMMIT TRANSACTION;

IF @createdListingsView = 1
BEGIN
  DROP VIEW dbo.Listings;
END;
